const entries = Object.entries(ENGLISH_TRANSLATIONS)
  .filter(([source]) => source.length >= 2)
  .sort(([a], [b]) => b.length - a.length);

const PLACEHOLDER_KEYS = {
  '名字': 'name',
  'Name': 'name',
  '俱乐部': 'club',
  'Club': 'club',
  '执教理念': 'philosophy',
  'Philosophy': 'philosophy',
  '教练名字': 'managerName',
  'Manager Name': 'managerName',
  'Coach Name': 'managerName',
  '俱乐部名字': 'clubName',
  'Club Name': 'clubName',
  '青训名字': 'youthName',
  'Youth Name': 'youthName'
};

const SOURCE_PLACEHOLDER_PATTERN = /\[(名字|俱乐部|执教理念|教练名字|俱乐部名字|青训名字)\]/g;
const TARGET_PLACEHOLDER_PATTERN = /\[([^\]]+)\]/g;

function escapeRegExp(value) {
  return value.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
}

function compilePlaceholderTemplate(source, target) {
  const captures = [];
  let cursor = 0;
  let pattern = '^';
  for (const match of source.matchAll(SOURCE_PLACEHOLDER_PATTERN)) {
    pattern += escapeRegExp(source.slice(cursor, match.index));
    pattern += '([\\s\\S]*?)';
    captures.push(PLACEHOLDER_KEYS[match[1]]);
    cursor = match.index + match[0].length;
  }
  if (captures.length === 0) return null;
  pattern += `${escapeRegExp(source.slice(cursor))}$`;
  return { pattern: new RegExp(pattern), captures, target };
}

const placeholderTemplates = Object.entries(ENGLISH_TRANSLATIONS)
  .map(([source, target]) => compilePlaceholderTemplate(source, target))
  .filter(Boolean)
  .sort((a, b) => b.pattern.source.length - a.pattern.source.length);

function translatePlaceholderTemplate(value) {
  for (const template of placeholderTemplates) {
    const match = value.match(template.pattern);
    if (!match) continue;
    const variables = {};
    template.captures.forEach((key, index) => {
      if (variables[key] === undefined) variables[key] = match[index + 1];
    });
    return template.target.replace(TARGET_PLACEHOLDER_PATTERN, (placeholder, name) => {
      const key = PLACEHOLDER_KEYS[name];
      return key && variables[key] !== undefined ? variables[key] : placeholder;
    });
  }
  return null;
}

function translateDynamicTail(value) {
  const text = String(value || '');
  if (ENGLISH_TRANSLATIONS[text] !== undefined) return ENGLISH_TRANSLATIONS[text];
  return text
    .match(/[^。！？]+[。！？]?/g)
    ?.map(segment => translateRenderedText(segment))
    .join(' ') || '';
}

const CHINESE_COUNTER_NUMBERS = {
  '一': '1',
  '二': '2',
  '三': '3',
  '四': '4',
  '五': '5',
  '六': '6',
  '七': '7',
  '八': '8',
  '九': '9',
  '十': '10'
};

function translateCounterNumber(value) {
  return CHINESE_COUNTER_NUMBERS[String(value)] || String(value);
}

function formatEnglishOrdinal(value) {
  const translated = translateCounterNumber(value);
  const number = Number.parseInt(translated, 10);
  if (!Number.isFinite(number)) return translated;
  const modulo100 = number % 100;
  const suffix = modulo100 >= 11 && modulo100 <= 13
    ? 'th'
    : number % 10 === 1
      ? 'st'
      : number % 10 === 2
        ? 'nd'
        : number % 10 === 3
          ? 'rd'
          : 'th';
  return `${number}${suffix}`;
}

