export function translateRenderedText(value) {
  if (!value || !/[\u3400-\u9fff]/.test(value)) return value;
  const whitespaceStart = value.match(/^\s*/)?.[0] || '';
  const whitespaceEnd = value.match(/\s*$/)?.[0] || '';
  const core = value.slice(whitespaceStart.length, value.length - whitespaceEnd.length);
  const exact = ENGLISH_TRANSLATIONS[core];
  if (exact !== undefined) return `${whitespaceStart}${exact}${whitespaceEnd}`;
  const templateTranslation = translatePlaceholderTemplate(core);
  if (templateTranslation !== null) return `${whitespaceStart}${templateTranslation}${whitespaceEnd}`;

  let translated = core;
  for (const [pattern, replacement] of DYNAMIC_RULES) {
    if (pattern.test(translated)) {
      translated = translated.replace(pattern, replacement);
      break;
    }
  }
  for (const [zh, en] of entries) translated = translated.split(zh).join(en);
  return `${whitespaceStart}${translated}${whitespaceEnd}`;
}
